worked_example.final_code:
import java.io.*;
import java.util.*;

class ReportSession implements AutoCloseable {
    private final String sessionId;
    private final List<String> log = new ArrayList<>();
    private boolean closed = false;

    ReportSession(String name) {
        this.sessionId = "RPT-" + name.hashCode();
        log.add("Session: " + name);
        System.out.println("[" + sessionId + "] opened");
    }

    void addEntry(String entry) {
        if (closed) throw new IllegalStateException("Session is closed");
        log.add(entry);
    }

    List<String> getLog() { return Collections.unmodifiableList(log); }

    @Override
    public void close() {
        if (!closed) {
            System.out.println("[" + sessionId + "] closed — " + log.size() + " entries");
            closed = true;
        }
    }
}

public class ReportGenerator {
    public static void main(String[] args) throws IOException {
        String csvData = "Aisha,5000\nRaj,3200\nPriya,8100\nVikram,1500";

        // Read data
        List<String[]> transactions = new ArrayList<>();
        try (BufferedReader reader = new BufferedReader(new StringReader(csvData))) {
            String line;
            while ((line = reader.readLine()) != null) {
                transactions.add(line.split(","));
            }
        }  // auto-close
        System.out.println("Read: " + transactions.size() + " rows");

        // Write report + track session
        StringWriter output = new StringWriter();
        try (ReportSession session = new ReportSession("Q4 Report");
             PrintWriter writer = new PrintWriter(output)) {

            writer.println("=== Report ===");
            double total = 0;
            for (String[] tx : transactions) {
                double amt = Double.parseDouble(tx[1].trim());
                total += amt;
                writer.printf("%-10s ₹%.0f%n", tx[0].trim(), amt);
                session.addEntry(tx[0].trim() + ": ₹" + amt);
            }
            writer.printf("%-10s ₹%.0f%n", "TOTAL", total);
        }  // writer closed first (declared 2nd), session closed 2nd (declared 1st) — REVERSE ORDER

        System.out.println(output);
    }
}

